ALTER TABLE `strength_observations` ADD `learner_correction` text DEFAULT '' NOT NULL;
CREATE TABLE `teach_assistant_graph_records` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `record_kind` text NOT NULL, `subject_ref` text NOT NULL, `summary` text NOT NULL, `provenance_ref` text NOT NULL, `status` text DEFAULT 'active' NOT NULL, `expires_at` text, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `teach_assistant_graph_user_idx` ON `teach_assistant_graph_records` (`user_id`);
CREATE INDEX `teach_assistant_graph_status_idx` ON `teach_assistant_graph_records` (`user_id`,`status`);
CREATE TABLE `teach_assistant_exchanges` (`id` text PRIMARY KEY NOT NULL, `sender_user_id` text NOT NULL, `recipient_user_id` text NOT NULL, `course_id` text NOT NULL, `sender_role` text NOT NULL, `recipient_role` text NOT NULL, `purpose` text NOT NULL, `projection` text NOT NULL, `consent_receipt_id` text NOT NULL, `idempotency_key` text NOT NULL, `expires_at` text NOT NULL, `status` text DEFAULT 'prepared' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `received_at` text, FOREIGN KEY (`sender_user_id`) REFERENCES `users`(`id`), FOREIGN KEY (`recipient_user_id`) REFERENCES `users`(`id`), FOREIGN KEY (`course_id`) REFERENCES `teach_courses`(`id`));
CREATE INDEX `teach_assistant_exchange_sender_idx` ON `teach_assistant_exchanges` (`sender_user_id`,`created_at`);
CREATE INDEX `teach_assistant_exchange_recipient_idx` ON `teach_assistant_exchanges` (`recipient_user_id`,`expires_at`);
CREATE UNIQUE INDEX `teach_assistant_exchange_idempotency_idx` ON `teach_assistant_exchanges` (`sender_user_id`,`idempotency_key`);
CREATE TABLE `teach_weekly_objectives` (`id` text PRIMARY KEY NOT NULL, `user_id` text NOT NULL, `title` text NOT NULL, `subject` text NOT NULL, `school_year` text NOT NULL, `week_start` text NOT NULL, `target_date` text NOT NULL, `status` text DEFAULT 'planned' NOT NULL, `evidence_refs` text DEFAULT '[]' NOT NULL, `created_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
CREATE INDEX `teach_weekly_objectives_user_week_idx` ON `teach_weekly_objectives` (`user_id`,`week_start`);
CREATE TABLE `teach_intervention_preferences` (`user_id` text PRIMARY KEY NOT NULL, `frequency` text DEFAULT 'off' NOT NULL, `contexts` text DEFAULT '[]' NOT NULL, `quiet_mode` integer DEFAULT true NOT NULL, `quiet_until` text, `max_daily_interventions` integer DEFAULT 0 NOT NULL, `updated_at` text DEFAULT CURRENT_TIMESTAMP NOT NULL, FOREIGN KEY (`user_id`) REFERENCES `users`(`id`));
